import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    allowed_commands = ['ls', 'echo', 'pwd', 'whoami', 'date']
    command_str = input("Enter command: ").strip()
    if not command_str:
        print("No command entered.")
        return
    try:
        parts = shlex.split(command_str)
    except ValueError as e:
        print(f"Invalid command syntax: {e}")
        return
    if not parts:
        print("No command entered.")
        return
    cmd = parts[0]
    if cmd not in allowed_commands:
        print(f"Command '{cmd}' is not allowed.")
        return
    try:
        result = subprocess.run(parts, capture_output=True, text=True, timeout=10)
        if result.stdout:
            print(result.stdout)
        if result.stderr:
            print(result.stderr, file=sys.stderr)
    except subprocess.TimeoutExpired:
        print("Command timed out.")
    except Exception as e:
        print(f"Error executing command: {e}")

